sql.if:
AND (
    EXISTS (
        SELECT 1 FROM follow_up_enrollment fe_s
        WHERE fe_s.register_id = r.id
          AND fe_s.status = 'active'
          AND fe_s.managing_department_id = #{departmentId}
    )
    OR EXISTS (
        SELECT 1 FROM follow_up_patient_profile fp_s
        WHERE fp_s.register_id = r.id
          AND fp_s.department_id = #{departmentId}
    )

    OR (
        NOT EXISTS (
            SELECT 1 FROM follow_up_enrollment fe_n
            WHERE fe_n.register_id = r.id AND fe_n.status = 'active'
        )
        AND NOT EXISTS (
            SELECT 1 FROM follow_up_patient_profile fp_n
            WHERE fp_n.register_id = r.id
        )
        AND r.deptment_id = #{departmentId}
    )

)

mapper.sql:
(
    EXISTS (
        SELECT 1 FROM follow_up_enrollment fe_en
        WHERE fe_en.register_id = r.id AND fe_en.status = 'active'
    )
    OR EXISTS (
        SELECT 1 FROM follow_up_patient_profile fp_en
        WHERE fp_en.register_id = r.id
    )
